package com.evolua.content.infrastructure.persistence; import com.evolua.content.domain.Trail; import com.evolua.content.domain.TrailRepository; import java.util.List; import org.springframework.stereotype.Repository; @Repository public class TrailPersistenceAdapter implements TrailRepository { private final TrailJpaRepository repository; public TrailPersistenceAdapter(TrailJpaRepository repository) { this.repository = repository; } public Trail save(Trail item) { TrailEntity entity = new TrailEntity(); entity.setId(item.id()); entity.setUserId(item.userId()); entity.setTitle(item.title()); entity.setDescription(item.description()); entity.setCategory(item.category()); entity.setPremium(item.premium()); entity.setCreatedAt(item.createdAt()); TrailEntity saved = repository.save(entity); return new Trail(saved.getId(), saved.getUserId(), saved.getTitle(), saved.getDescription(), saved.getCategory(), saved.getPremium(), saved.getCreatedAt()); } public List<Trail> findAllByUserId(String userId) { return repository.findAllByUserId(userId).stream().map(saved -> new Trail(saved.getId(), saved.getUserId(), saved.getTitle(), saved.getDescription(), saved.getCategory(), saved.getPremium(), saved.getCreatedAt())).toList(); } }
